sql:
SELECT AVG(function_confidence) AS average_signaling_confidence
FROM sequence_functions
WHERE function_name LIKE '%Signaling%';

SELECT publication_title
FROM sequence_publications
WHERE protein_id = 1;

SELECT name 
FROM protein_sequences 
WHERE confidence_score = (SELECT MAX(confidence_score) FROM protein_sequences);

SELECT COUNT(*) AS count
FROM sequence_functions
WHERE function_name = 'Immune response';

external_knowledge:
- The accession number is a unique identifier for a protein sequence, and 'XP_032614344.1' is a specific accession number of interest; 
- The species name refers to the scientific name of the species to which the protein belongs; 
- The function name refers to the biological function of the protein.

sql:
SELECT protein_id, name, sequence_type
FROM protein_sequences
WHERE protein_id > 0 AND sequence_type = 'Coding';

SELECT COUNT(DISTINCT protein_id)
FROM sequence_diseases
WHERE disease_name = 'Cancer';
